var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"메스해르츠 채널에서 전해드리는 핫이슈 시간!","JPN":"マスヘルツチャンネルでお送りするホットなニュースのお時間！","ENG":"Hot issues to you from the Masshertz channel!","TWN":"現在是梅斯赫茲頻道的熱點話題時間！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"현재 화제가 되고 있죠? 시니어를 암살하고 관리국의 수배를 받고 있는 그 인물!","JPN":"最近話題になっていますね？　シニアを暗殺して管理局から指名手配されているあの人物！","ENG":"It's what everyone is talking about right now. The Administration's most wanted for assassinating a Senior!","TWN":"如今被討論最多的，是這位暗殺了Senior並被管理局通緝的人物。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"유명 영화배우 스완 클레어의 민낯에 대해서 가장 잘 알고 있는 매니저를 모셨는데요.","JPN":"有名女優、スワン・クレアの素顔について一番よく知るマネージャーさんをお招きしました。","ENG":"We are currently with the famous actress, Swan Claire's manager who knows all her secrets.","TWN":"我們有幸請來了最了解著名電影演員史旺·克萊爾秘密的經紀人。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"안녕하세요, 스완 클레어의 매니저분 맞으시죠?","JPN":"こんにちは、スワン・クレアのマネージャーさんですよね？","ENG":"Hello. You are Swan Claire's manager, correct?","TWN":"你好，你就是史旺·克萊爾的經紀人吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아, 그러니까요!","JPN":"だから、そうですって！","ENG":"Oh, come on!","TWN":"啊，沒錯！就是我！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"계속 말했잖아요! 저는 그 망할 년이 처음부터 그런 짓을 벌일지 알고 있었다니깐요?","JPN":"何度も言ってるじゃないですか！　私はあのクソ女があんなことをするって、最初からわかってたんです！","ENG":"I keep telling you! I knew that wretched bitch would do something like this from the second I met her!","TWN":"我早就說過了！我一開始就知道那個瘋女人會幹出這種事！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"아하하. 흥분을 좀 가라앉히시고요.","JPN":"あはは。まあまあ少し落ち着いて。","ENG":"Ah hah hah. Why don't you calm down a bit.","TWN":"啊哈哈。請、請冷靜點吧……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"갑질이란 갑질은 다 하지, 시도 때도 없이 스케줄 변경하지, 약점 잡아서 협박하지……!","JPN":"偉そうにあれこれ言ってくるわ、しょっちゅうスケジュールを変更するわ、弱点を掴んで脅すわ……！","ENG":"She's bossy! Keeps changing her schedules on a whim! And even blackmailing others with their secrets...!","TWN":"太不講道理了！隨時隨地更改日程，還拼命揪住我的弱點勒索威脅……!"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아주 지긋지긋했다고요!","JPN":"もう、うんざりしてたんですよ！","ENG":"I'm sick of all of it!","TWN":"我真是受夠了！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"음? 약점이라고요? 그건 어떤 약점이죠?","JPN":"えっ？　弱点？　それはどういう弱点なんですか？","ENG":"Hmm? Secret? What kind of secret?","TWN":"嗯？弱點？什麼樣的弱點？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아! 그, 그건!","JPN":"あっ！　そ、それは！","ENG":"Oh! Th-that's!","TWN":"啊！那、那個！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MANAGER_SWANSONG_NPC_NULL","text":{"KOREA":"아하하, 이건 편집해 주시겠어요……?","JPN":"あはは、これはカットしてもらえますか……？","ENG":"Ah hah hah! Could you edit that out, please...?","TWN":"啊哈哈，這段能幫我剪掉嗎……？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"MANAGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"……한편 수배 중인 스완이 제작한 드라마가 역대급 시청률을 기록하고 있는데요.","JPN":"……一方、指名手配中のスワンが製作したドラマが史上最高の視聴率を記録しています。","ENG":"...On a side note, the drama series produced by Swan Claire, who is currently wanted, is hitting record-breaking viewership ratings right now.","TWN":"……另一方面，通緝中的史旺製作的電視劇創下了歷史最高收視率。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"그녀의 범죄가 드라마와 상당히 일치하며, 유례없는 극장형 범죄라는 점이 화제입니다.","JPN":"彼女の犯罪がドラマと相当一致しており、前例のない劇場型の犯罪であるというところが話題となっていますね。","ENG":"People are saying that her crimes and the series seem to overlap, and are calling it an unprecedented theatrical crime.","TWN":"她的犯罪與電視劇情節高度吻合，被稱為前所未有的戲劇性犯罪，引起了熱議。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"일각에서는 범죄자의 미화가 아니냐는 논란이 있는 가운데.","JPN":"一部では犯罪者を美化するのではないかという意見も出ている中、","ENG":"Among the controversy over whether it is a glorification of the criminal,","TWN":"也有人質疑這是否是在美化犯罪者，引發了爭議。"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"감독과 스폰서는 각본가를 교체하여 드라마의 시즌2를 기획하고 있다고 발표하여…….","JPN":"監督とスポンサーは脚本家を再雇用し、ドラマのシーズン2を企画しているとの発表を……","ENG":"the director and sponsor have announced that they will be replacing the scriptwriter and are planning for a second season...","TWN":"導演和贊助商宣佈將更換編劇，計畫製作電視劇的第二季……"},"stage":{"bg":"SKYLINE_NIGHT2","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이 천장… 이젠 낯설지가 않네.","JPN":"この天井……もう見飽きたな。","ENG":"This ceiling... It's so familiar now.","TWN":"病房的天花板啊……現在也不是那麼陌生了。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님! 제가 밥 가져왔어요!","JPN":"先輩！　ご飯を持ってきました！","ENG":"Mina! I brought you your food!","TWN":"前輩，我給你帶了些吃的！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘?","JPN":"ノエル？","ENG":"Noelle?","TWN":"洛艾兒？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"왜 네가 그걸 가져와? 너 다리에 깁스하고 있잖아. 의사가 특히 꼬리뼈를 조심하라던데.","JPN":"何であなたがそんなことするの？　脚にギプスをつけているのに。医者が特に尾骨には気を付けろって言ったよね。","ENG":"Why are you bringing that? You have a cast on your leg. Didn't the doctor tell you to be especially careful about your tailbone?","TWN":"為什麼是你給我帶來？你腿上打著石膏，而且醫生說要特別小心你的尾骨。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아요. 선배님이 싸인 해 주신 덕분에 금방 나았…","JPN":"大丈夫です。先輩がしてくれたサインのおかげですぐ治っ……","ENG":"It's all right. You signed my cast, so I'll be good in no ti–","TWN":"沒關係，多虧了你的親筆簽名，我很快就好……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꺄앗!!","JPN":"きゃあっ！！","ENG":"Kyaah!","TWN":"呀啊！！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐아앙, 괜찮으세요?","JPN":"ふええん、大丈夫ですか？","ENG":"Waah... Are you okay?","TWN":"嗚嗚，你還好嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…정수리가 국 때문에 뜨거워.","JPN":"……頭が汁のせいで熱い。","ENG":"...You poured hot soup all over my head.","TWN":"……湯灑在我頭上了。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};